import{i as e,r as t,s as n,t as r}from"./app-BDbP51_p.js";var i=JSON.parse(`{"path":"/redaction-processing/extract_fonts.html","title":"extract_fonts — Font Detection Module","lang":"en-US","frontmatter":{},"git":{"updatedTime":1774704928000,"contributors":[{"name":"JaguarM","username":"JaguarM","email":"39597011+JaguarM@users.noreply.github.com","commits":2,"url":"https://github.com/JaguarM"}],"changelog":[{"hash":"3bbb491f17913ec6288159d2b53d03c92c805a63","time":1774704928000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Made that shit modular with django apps"},{"hash":"bf08d857bceb2e8319cea774aaea7faacbe2e436","time":1774474422000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Detect PDF fonts &#x26; wire to frontend"}]},"filePathRelative":"redaction-processing/extract_fonts.md"}`),a={name:`extract_fonts.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="extract-fonts-—-font-detection-module" tabindex="-1"><a class="header-anchor" href="#extract-fonts-—-font-detection-module"><span>extract_fonts — Font Detection Module</span></a></h1><p><strong>File:</strong> <code>text_tool/logic/extract_fonts.py</code></p><p>Detects the dominant font used in a PDF and maps it to one of the <code>.ttf</code> files available in <code>assets/fonts/</code>. The result is returned to the frontend as <code>suggested_font</code> and <code>suggested_size</code> so the toolbar and width calculator are pre-configured on every PDF load.</p><hr><h2 id="how-it-fits-into-the-pipeline" tabindex="-1"><a class="header-anchor" href="#how-it-fits-into-the-pipeline"><span>How it fits into the pipeline</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">POST /analyze-pdf</span>
<span class="line">  └── process_pdf()              # ProcessRedactions.py</span>
<span class="line">        └── extracts text_spans  # PyMuPDF span data, one entry per text run</span>
<span class="line">  └── detect_dominant_font()     # text_tool.logic.extract_fonts   ← this module</span>
<span class="line">        └── returns font_file, font_size, pdf_font_name</span>
<span class="line">  └── JsonResponse</span>
<span class="line">        ├── suggested_font       # e.g. &quot;times.ttf&quot;</span>
<span class="line">        └── suggested_size       # e.g. 12.0</span>
<span class="line"></span>
<span class="line">Browser (pdf-viewer.js)</span>
<span class="line">  └── sets els.font.value  = suggested_font</span>
<span class="line">  └── sets els.size.value  = suggested_size</span>
<span class="line">  └── seeds every redaction&#39;s settings.font / settings.size</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="public-api" tabindex="-1"><a class="header-anchor" href="#public-api"><span>Public API</span></a></h2><h3 id="detect-dominant-font-text-spans-available-fonts" tabindex="-1"><a class="header-anchor" href="#detect-dominant-font-text-spans-available-fonts"><span><code>detect_dominant_font(text_spans, available_fonts)</code></span></a></h3><p>Analyses pre-extracted text spans and returns the font that accounts for the most body-text characters in the document.</p><p><strong>Parameters</strong></p><table><thead><tr><th>Name</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>text_spans</code></td><td><code>list[dict]</code></td><td>Span list produced by <code>ProcessRedactions.process_pdf</code>. Each entry: <code>{&quot;page&quot;: int, &quot;text&quot;: str, &quot;font&quot;: {&quot;size&quot;: float, &quot;flags&quot;: int, &quot;matched_font&quot;: str}}</code></td></tr><tr><td><code>available_fonts</code></td><td><code>list[str]</code></td><td><code>.ttf</code> filenames present in <code>assets/fonts/</code> (from <code>width_calculator.get_available_fonts()</code>). Only fonts in this list can be returned.</td></tr></tbody></table><p><strong>Returns</strong> — <code>dict</code></p><table><thead><tr><th>Key</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>font_file</code></td><td><code>str | None</code></td><td>Filename to load, e.g. <code>&quot;times.ttf&quot;</code>. <code>None</code> if the dominant font has no match in <code>available_fonts</code>.</td></tr><tr><td><code>font_size</code></td><td><code>float</code></td><td>Most common size (in points) for that font across all spans.</td></tr><tr><td><code>pdf_font_name</code></td><td><code>str</code></td><td>Raw internal PDF font name, e.g. <code>&quot;TimesNewRomanPSMT&quot;</code>.</td></tr></tbody></table><p><strong>Example</strong></p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> text_tool<span class="token punctuation">.</span>logic<span class="token punctuation">.</span>extract_fonts <span class="token keyword">import</span> detect_dominant_font</span>
<span class="line"><span class="token keyword">from</span> text_tool<span class="token punctuation">.</span>logic<span class="token punctuation">.</span>width_calculator <span class="token keyword">import</span> get_available_fonts</span>
<span class="line"></span>
<span class="line">result <span class="token operator">=</span> detect_dominant_font<span class="token punctuation">(</span>spans<span class="token punctuation">,</span> get_available_fonts<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment"># {&quot;font_file&quot;: &quot;times.ttf&quot;, &quot;font_size&quot;: 12.0, &quot;pdf_font_name&quot;: &quot;TimesNewRomanPSMT&quot;}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="detection-algorithm" tabindex="-1"><a class="header-anchor" href="#detection-algorithm"><span>Detection algorithm</span></a></h2><ol><li><strong>Aggregate character counts</strong> — iterate every span; accumulate the number of characters per <code>(pdf_font_name, size)</code> pair.</li><li><strong>Filter noise</strong> — discard any font whose total character count is below <code>MIN_CHARS</code> (currently <code>35</code>). This eliminates page headers, footnotes, watermarks, and one-off decorative glyphs that are not representative of body text.</li><li><strong>Pick dominant font</strong> — the font with the highest total character count after filtering.</li><li><strong>Pick dominant size</strong> — for that font, the size bucket with the most characters.</li><li><strong>Map to <code>.ttf</code></strong> — run the PDF internal name through <code>FONT_MAP</code> (see below); return the first matching <code>.ttf</code> that exists in <code>available_fonts</code>.</li></ol><hr><h2 id="font-mapping-table-font-map" tabindex="-1"><a class="header-anchor" href="#font-mapping-table-font-map"><span>Font mapping table (<code>FONT_MAP</code>)</span></a></h2><p>Evaluated top-to-bottom; first keyword match wins.</p><table><thead><tr><th>Keywords in PDF font name</th><th>Mapped <code>.ttf</code> file</th></tr></thead><tbody><tr><td><code>times</code>, <code>roman</code></td><td><code>times.ttf</code></td></tr><tr><td><code>courier</code></td><td><code>courier_new.ttf</code></td></tr><tr><td><code>arial</code>, <code>helvetica</code></td><td><code>arial.ttf</code></td></tr><tr><td><code>calibri</code></td><td><code>calibri.ttf</code></td></tr><tr><td><code>verdana</code></td><td><code>verdana.ttf</code></td></tr><tr><td><code>segoe</code></td><td><code>segoe_ui.ttf</code></td></tr></tbody></table><p>If no keyword matches, or the matched <code>.ttf</code> is not present in <code>available_fonts</code>, <code>font_file</code> is returned as <code>None</code> and the frontend falls back to whatever is currently selected in the font dropdown.</p><hr><h2 id="constants" tabindex="-1"><a class="header-anchor" href="#constants"><span>Constants</span></a></h2><table><thead><tr><th>Name</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>MIN_CHARS</code></td><td><code>35</code></td><td>Minimum character count for a font to be considered significant. Raise to be more conservative; lower to detect fonts in short documents.</td></tr></tbody></table><hr><h2 id="standalone-script" tabindex="-1"><a class="header-anchor" href="#standalone-script"><span>Standalone script</span></a></h2><p>The module doubles as a CLI tool for auditing font metadata across a local directory tree. Run directly with Python:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">python text_tool/logic/extract_fonts.py</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>The <code>base_directory</code> and <code>target_directories</code> at the bottom of the file control which folders are scanned. For each PDF found it prints every recognised font along with its character count, type, and encoding, and tags the highest-use font as <code>[PRIMARY FONT]</code>.</p><p>This is useful for verifying that the <code>FONT_MAP</code> keywords cover the fonts present in a new corpus before uploading documents to the tool.</p><hr><h2 id="adding-a-new-font" tabindex="-1"><a class="header-anchor" href="#adding-a-new-font"><span>Adding a new font</span></a></h2><ol><li>Drop the <code>.ttf</code> file into <code>assets/fonts/</code>.</li><li>Add a row to <code>FONT_MAP</code> in <code>extract_fonts.py</code>:<div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&quot;myfont&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;alternate-name&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token string">&quot;myfont.ttf&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div></li><li>Keywords are matched against the <strong>lowercase</strong> PDF-internal font name, so use lowercase in the keyword list.</li><li>Place the new row before any existing row whose keywords could accidentally match the same font name.</li></ol>`,36)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};